import{c as l,Q as i,j as e,m as t}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"子任务","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/task-management/subtasks.md","filePath":"using-system/task-management/subtasks.md"}'),r={name:"using-system/task-management/subtasks.md"};function n(o,a,s,h,u,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="子任务" tabindex="-1">子任务 <a class="header-anchor" href="#子任务" aria-label="Permalink to &quot;子任务&quot;">​</a></h1><p>将复杂任务拆分为多个子任务进行管理，便于分工协作和进度跟踪。</p><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>子任务功能允许您将一个复杂的主任务分解为多个独立的子任务，适用于以下场景：</p><ul><li><strong>评分评级任务</strong>：分解为财报收集、AI校对、评分评级、PPT汇报、报告归档等子任务</li></ul><h2 id="创建子任务" tabindex="-1">创建子任务 <a class="header-anchor" href="#创建子任务" aria-label="Permalink to &quot;创建子任务&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li><p><strong>打开任务创建窗口</strong></p><ul><li>进入任务创建窗口</li></ul></li><li><p><strong>进入子任务管理</strong></p><ul><li>在任务创建窗口找到「添加子任务」标签页</li><li>点击「添加子任务」按钮 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525144545204.png" alt=""></li></ul></li><li><p><strong>填写子任务信息</strong></p><ul><li><strong>子任务标题</strong>：输入子任务的标题（必填）</li><li><strong>负责人</strong>：选择子任务的负责人（可选，默认为主任务负责人）</li></ul><p>打开详情，可填写：</p><ul><li><strong>截止时间</strong>：设置子任务的截止日期和时间（可选）</li><li><strong>权重分</strong>：设置子任务的权重分（可选）</li><li><strong>描述</strong>：添加子任务的详细描述（可选） <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525140119070.png" alt="子任务创建窗口"></li></ul></li><li><p><strong>保存子任务</strong></p><ul><li>点击「保存」按钮</li><li>子任务将显示在子任务列表中 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525121504534.png" alt="子任务管理"></li></ul></li></ol><h2 id="子任务管理" tabindex="-1">子任务管理 <a class="header-anchor" href="#子任务管理" aria-label="Permalink to &quot;子任务管理&quot;">​</a></h2><h3 id="查看子任务列表" tabindex="-1">查看子任务列表 <a class="header-anchor" href="#查看子任务列表" aria-label="Permalink to &quot;查看子任务列表&quot;">​</a></h3><p>子任务列表显示以下信息：</p><ul><li>子任务标题</li><li>负责人</li><li>截止时间</li></ul><blockquote><p>更多内容在子任务详情页查看</p></blockquote><h3 id="编辑子任务" tabindex="-1">编辑子任务 <a class="header-anchor" href="#编辑子任务" aria-label="Permalink to &quot;编辑子任务&quot;">​</a></h3><ol><li>点击子任务的「标题」进入详情页</li><li>修改子任务信息（标题、负责人、截止时间等）</li><li>点击「保存」按钮 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525145341539.png" alt=""></li></ol><h3 id="删除子任务" tabindex="-1">删除子任务 <a class="header-anchor" href="#删除子任务" aria-label="Permalink to &quot;删除子任务&quot;">​</a></h3><ul><li>右键点击子任务，选择「删除」选项</li><li>在确认对话框中点击「确定」</li><li>已删除的子任务无法恢复，请谨慎操作 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525150214082.png" alt=""></li></ul><h3 id="子任务详情" tabindex="-1">子任务详情 <a class="header-anchor" href="#子任务详情" aria-label="Permalink to &quot;子任务详情&quot;">​</a></h3><ul><li>点击子任务标题进入详情页</li><li>查看子任务的完整信息</li><li>添加评论和附件</li><li>查看操作历史</li></ul><h2 id="进度统计" tabindex="-1">进度统计 <a class="header-anchor" href="#进度统计" aria-label="Permalink to &quot;进度统计&quot;">​</a></h2><h3 id="完成比例" tabindex="-1">完成比例 <a class="header-anchor" href="#完成比例" aria-label="Permalink to &quot;完成比例&quot;">​</a></h3><ul><li>实时计算子任务的完成比例</li><li>在任务详情页显示整体进度</li><li>进度条可视化展示完成情况</li></ul><h3 id="进度详情" tabindex="-1">进度详情 <a class="header-anchor" href="#进度详情" aria-label="Permalink to &quot;进度详情&quot;">​</a></h3><ul><li>已完成子任务数量</li><li>未完成子任务数量</li><li>每个子任务的状态分布</li></ul><h3 id="进度报表" tabindex="-1">进度报表 <a class="header-anchor" href="#进度报表" aria-label="Permalink to &quot;进度报表&quot;">​</a></h3><ul><li>导出子任务进度报表</li><li>支持Excel和PDF格式</li><li>包含完成时间、负责人、状态等信息</li></ul><h2 id="高级设置" tabindex="-1">高级设置 <a class="header-anchor" href="#高级设置" aria-label="Permalink to &quot;高级设置&quot;">​</a></h2><h3 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h3><p>设置子任务之间的依赖关系：</p><ul><li><strong>前置子任务</strong>：必须先完成某个子任务才能开始当前子任务</li><li><strong>后置子任务</strong>：完成当前子任务后自动触发下一个子任务</li></ul><h3 id="通知设置" tabindex="-1">通知设置 <a class="header-anchor" href="#通知设置" aria-label="Permalink to &quot;通知设置&quot;">​</a></h3><p>为子任务设置提醒：</p><ul><li>子任务截止前提醒</li><li>子任务状态变更通知</li><li>负责人变更通知</li></ul><h3 id="权限设置" tabindex="-1">权限设置 <a class="header-anchor" href="#权限设置" aria-label="Permalink to &quot;权限设置&quot;">​</a></h3><ul><li>设置子任务的查看权限</li><li>设置子任务的编辑权限</li><li>设置子任务的完成权限</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="任务分解原则" tabindex="-1">任务分解原则 <a class="header-anchor" href="#任务分解原则" aria-label="Permalink to &quot;任务分解原则&quot;">​</a></h3><ul><li>子任务应具有独立性和可完成性</li><li>每个子任务最好由一个人负责</li><li>子任务数量建议控制在5-10个之间</li></ul><h3 id="负责人分配" tabindex="-1">负责人分配 <a class="header-anchor" href="#负责人分配" aria-label="Permalink to &quot;负责人分配&quot;">​</a></h3><ul><li>根据职责和专长分配子任务</li><li>确保负责人有足够的时间和资源</li><li>及时通知负责人有关子任务的信息</li></ul><h3 id="时间管理" tabindex="-1">时间管理 <a class="header-anchor" href="#时间管理" aria-label="Permalink to &quot;时间管理&quot;">​</a></h3><ul><li>合理设置子任务的截止时间</li><li>避免子任务截止时间过于集中</li><li>考虑主任务的整体截止时间</li></ul><h3 id="沟通协作" tabindex="-1">沟通协作 <a class="header-anchor" href="#沟通协作" aria-label="Permalink to &quot;沟通协作&quot;">​</a></h3><ul><li>定期同步子任务进展</li><li>及时沟通遇到的问题</li><li>保持信息透明和共享</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-如何设置子任务的依赖关系" tabindex="-1">Q：如何设置子任务的依赖关系？ <a class="header-anchor" href="#q-如何设置子任务的依赖关系" aria-label="Permalink to &quot;Q：如何设置子任务的依赖关系？&quot;">​</a></h3><p>A：在编辑子任务时，找到「依赖关系」选项：</p><ul><li>选择前置子任务（必须先完成的子任务）</li><li>选择后置子任务（完成后自动触发的子任务）</li><li>保存后，系统会自动管理依赖关系</li></ul><h3 id="q-子任务完成后会怎样" tabindex="-1">Q：子任务完成后会怎样？ <a class="header-anchor" href="#q-子任务完成后会怎样" aria-label="Permalink to &quot;Q：子任务完成后会怎样？&quot;">​</a></h3><p>A：子任务完成后：</p><ul><li>自动更新主任务的进度</li><li>触发后置子任务的通知</li><li>记录完成时间和完成人</li></ul><h3 id="q-可以为子任务添加附件吗" tabindex="-1">Q：可以为子任务添加附件吗？ <a class="header-anchor" href="#q-可以为子任务添加附件吗" aria-label="Permalink to &quot;Q：可以为子任务添加附件吗？&quot;">​</a></h3><p>A：可以，每个子任务都支持：</p><ul><li>添加附件文件</li><li>添加评论和备注</li><li>记录操作历史</li></ul><h3 id="q-如何统计多个任务的子任务进度" tabindex="-1">Q：如何统计多个任务的子任务进度？ <a class="header-anchor" href="#q-如何统计多个任务的子任务进度" aria-label="Permalink to &quot;Q：如何统计多个任务的子任务进度？&quot;">​</a></h3><p>A：可以通过以下方式：</p><ul><li>在任务列表页面查看整体进度</li><li>导出任务进度报表</li><li>使用筛选功能查看特定状态的子任务</li></ul><h3 id="q-子任务可以独立设置提醒吗" tabindex="-1">Q：子任务可以独立设置提醒吗？ <a class="header-anchor" href="#q-子任务可以独立设置提醒吗" aria-label="Permalink to &quot;Q：子任务可以独立设置提醒吗？&quot;">​</a></h3><p>A：可以，每个子任务都可以：</p><ul><li>设置独立的截止时间</li><li>设置独立的提醒方式</li><li>设置独立的通知对象</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/using-system/task-management/create-task/">创建/编辑任务</a></li><li><a href="/using-system/task-management/attachments.html">添加附件</a></li><li><a href="/using-system/task-management/reminders.html">任务提醒</a></li><li><a href="/using-system/task-management/execute.html">任务执行</a></li></ul>',62)])])}const q=l(r,[["render",n]]);export{m as __pageData,q as default};
